#[test]
fn test_symmetry_generate_to_cell() {
    let sg = SymmetryGenerate;
    let cell = sg.to_cell();
    match cell {
        Cell::Flag(name) => assert_eq!(name, "SYMMETRY_GENERATE"),
        _ => panic!("Expected Cell::Flag, got {:?}", cell),
    }
}

#[test]
fn test_spectral_kpoint_path_multiple_entries() {
    let rows = vec![
        CellValue::Array(vec![
            CellValue::Float(0.3333333333),
            CellValue::Float(0.375),
            CellValue::Float(0.3333333333),
        ]),
        CellValue::Array(vec![
            CellValue::Float(0.3333333333),
            CellValue::Float(0.375),
            CellValue::Float(0.0),
        ]),
    ];
    let result = SpectralKpointPath::from_block_rows(&rows).unwrap();
    assert_eq!(result.points.len(), 2);
}

#[test]
fn test_spectral_kpoints_list_multiple_entries() {
    let rows = vec![
        CellValue::Array(vec![
            CellValue::Float(0.0),
            CellValue::Float(0.0),
            CellValue::Float(0.0),
            CellValue::Float(0.25),
        ]),
        CellValue::Array(vec![
            CellValue::Float(0.5),
            CellValue::Float(0.0),
            CellValue::Float(0.0),
            CellValue::Float(0.75),
        ]),
    ];
    let result = SpectralKpointsList::from_block_rows(&rows).unwrap();
    assert_eq!(result.kpts.len(), 2);
    assert_eq!(result.kpts[0].weight, 0.25);
}

